import{c as a,bM as e,bh as r,bk as d,r as l,a0 as h}from"./chunks/framework.DXtQZ1HH.js";const m=JSON.parse('{"title":"无冥","description":"","frontmatter":{"order":2},"headers":[],"relativePath":"地图/幽冥血海/无冥.md","filePath":"地图/幽冥血海/无冥.md","lastUpdated":0}'),n={name:"地图/幽冥血海/无冥.md"};function i(s,t,o,b,c,x){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="无冥" tabindex="-1">无冥 <a class="header-anchor" href="#无冥" aria-label="Permalink to “无冥”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">木类材料</th><th style="text-align:center;">矿类材料</th><th style="text-align:center;">布类材料</th></tr></thead><tbody><tr><td style="text-align:center;">紫云芝</td><td style="text-align:center;">刺冥骨</td><td style="text-align:center;">乌烟绒</td></tr></tbody></table><h2 id="孤魂岭" tabindex="-1">孤魂岭 <a class="header-anchor" href="#孤魂岭" aria-label="Permalink to “孤魂岭”">​</a></h2><h3 id="獒狠" tabindex="-1">獒狠 <a class="header-anchor" href="#獒狠" aria-label="Permalink to “獒狠”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>铁锤连击：连续挥动铁锤攻击前方</td></tr><tr><td>修罗铁锁：跃起将尖刺一头的铁链向敌人方向伸出后勾回，抓住敌人一起落地，对敌人造成伤害，并降低其吸血|治疗效果</td></tr><tr><td>野蛮冲撞：奋起全身力量，朝前方猛冲一击，伤害并晕眩（连续释放3次，每次冲撞的距离和伤害值都会逐渐提高，第3次冲撞后Boss陷入短暂疲惫状态）</td></tr><tr><td>魔牛追击：追踪敌人，一小段时间后向前跃起，持锤猛烈斩击落地，对敌人造成伤害，并降低其吸血|治疗效果</td></tr><tr><td>冥怒之锤：旋转铁锤朝敌人移动，而后铁锤猛击地面，带动场景上方石块坠落</td></tr><tr><td>蛮牛守护：怒吼给自身添加蛮牛守护（受到的伤害降低，同时受伤时沉默敌人，持续5秒钟）</td></tr></tbody></table><p>掉落道具：无冥防具制作书</p><h2 id="通冥铁索" tabindex="-1">通冥铁索 <a class="header-anchor" href="#通冥铁索" aria-label="Permalink to “通冥铁索”">​</a></h2><h3 id="亚窳" tabindex="-1">亚窳 <a class="header-anchor" href="#亚窳" aria-label="Permalink to “亚窳”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>利爪扑击：朝前跳跃，挥动爪子攻击前方</td></tr><tr><td>狂暴撕咬：按住敌人，撕咬3次，伤害并降低敌人治疗和吸血效果</td></tr><tr><td>黑雨裁决：后跳一步，在上空召唤一片黑云，黑云会降落黑雨（boss处于黑雨范围内可回血，同时对玩家造成扣血）。黑云会先在原地停留一会，然后朝敌人移动</td></tr><tr><td>混乱水球：在左、右两侧各凝聚一颗水球。水球存在期间，每隔一段时间朝8个方向发射子弹，造成伤害并混乱，可被打破</td></tr><tr><td>玄冥水龙：从道路两侧的水引出水龙，先垂直往上窜出，随后掉转头从上朝下攻击并成沉默敌人，重复攻击3次</td></tr><tr><td>水流喷射：抽取道路两边的水，聚于口中，随后朝斜下方射出水流，造成伤害并减蓝</td></tr><tr><td>硬化皮肤：皮肤变得硬化，持续一段时间（降低受到的伤害，且如果期间被攻击将会使攻击者晕眩）</td></tr></tbody></table><p>掉落道具：无冥武器制作书（第一心法）</p><h2 id="通冥铁索隐藏" tabindex="-1">通冥铁索隐藏 <a class="header-anchor" href="#通冥铁索隐藏" aria-label="Permalink to “通冥铁索隐藏”">​</a></h2><p>通过观察<strong>背景</strong>中山上符文的顺序，<strong>按顺序</strong>踩铁索下的符文台，开启<strong>隐藏入口</strong></p><img src="'+l+'" alt="通冥铁索隐藏" style="zoom:67%;"><h3 id="波儿象" tabindex="-1">波儿象 <a class="header-anchor" href="#波儿象" aria-label="Permalink to “波儿象”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>被动：Boss的攻击力会随防御力提升而提升。战斗过程中，每当boss血量低于75%/50%/25%时会获得1层防御属性提升，共3层</td></tr><tr><td>双向头槌：在原地左右甩头攻击，造成二连击</td></tr><tr><td>狂牙冲撞：用獠牙向前顶撞攻击，随后后跳再次向前跃撞</td></tr><tr><td>疾风奔袭：用后蹄划拉地板2下，随后朝前急速奔跑1次或3次</td></tr><tr><td>魔嘴血噬：身体蜷缩蓄力，蓄力结束后张开大嘴将周围的敌人都吸入嘴边，吸引结束后大口噬咬前方敌人，并恢复自身一定比例的血量。蓄力期间玩家可造成足够的伤害将其打断</td></tr><tr><td>蛮兽尖刺：用獠牙低头朝前一拱，将敌人顶飞至自己的后上方，随后背上射出大量尖刺持续轰击后上方</td></tr><tr><td>铁甲反弹：跳跃转身背朝玩家匍匐在地上，获得额外反伤效果，动作结束后获得防御加成，持续10s</td></tr></tbody></table><p>掉落道具：无冥武器制作书（第二心法）</p><h2 id="播冢山巅" tabindex="-1">播冢山巅 <a class="header-anchor" href="#播冢山巅" aria-label="Permalink to “播冢山巅”">​</a></h2><h3 id="西冥鹰帝" tabindex="-1">西冥鹰帝 <a class="header-anchor" href="#西冥鹰帝" aria-label="Permalink to “西冥鹰帝”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>被动：西冥鹰帝存活时，降低场上玩家吸血和回血效果；仅西冥鹰帝存活时，西冥鹰帝的暴击提高</td></tr><tr><td>冥焰禁锢：西冥鹰帝控制冥鹰，冥鹰朝目标方向发射出一道冥焰子弹，若命中则形成冥牢禁锢敌人</td></tr><tr><td>绝命冲刺：西冥鹰帝控制冥鹰，冥鹰朝前急速冲刺到另一侧，而后返身往回冲刺回到西冥鹰帝身后（对碰到的敌人造成伤害并使其受到的伤害提高）</td></tr><tr><td>冥爪禁锢：西冥鹰帝朝前放出鹰爪短暂晕眩并沉默敌人，而后控制冥鹰飞向敌人，连续多次攻击前方（并降低其吸血和治疗效果）</td></tr><tr><td>漫天冥石：西冥鹰帝控制冥鹰，冥鹰在全屏召唤多道冥火石下坠，落地后遗留在地面（冥火石可击碎），一小段时间后，冥火石爆炸对周围的敌人造成伤害和混乱</td></tr><tr><td>冥鹰守护：西冥鹰帝控制冥鹰，冥鹰张喙啼叫，给西冥鹰帝添加鹰之守护，提高攻击力</td></tr></tbody></table><h3 id="西冥熊帝" tabindex="-1">西冥熊帝 <a class="header-anchor" href="#西冥熊帝" aria-label="Permalink to “西冥熊帝”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>被动：西冥熊帝存活时，降低场上玩家攻击属性；仅西冥熊帝存活时，西冥熊帝的吸血和反伤提高</td></tr><tr><td>狂暴掌击：西冥熊帝控制冥熊，奔跑至敌人面前，连续掌击地面两次</td></tr><tr><td>绝命冲撞：西冥熊帝控制冥熊前冲，冥熊朝前狂奔冲撞到另一侧，而后返身往回狂奔冲撞回到西冥熊帝脚边（对碰到的敌人造成伤害并使其造成的伤害下降）</td></tr><tr><td>狂怒沙暴：西冥熊帝控制冥熊，冥熊踏地，由内至外释放多道沙柱，一段时间后冥熊再次踏地释放多道沙柱</td></tr><tr><td>冥熊之怒：西冥熊帝控制冥熊，冥熊朝前怒吼，使当前地面存在的所有冥火石提前爆炸，同时冥熊额外释放冲击波伤害并晕眩敌人</td></tr><tr><td>冥熊守护：在自身前方生成熊之护盾吸收伤害，持续5秒</td></tr></tbody></table><p>掉落道具：<a href="/zmxy4-helpPages/角色相关/饰品/常见主线饰品.html#无冥风铃">无冥风铃制作书</a></p><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="无冥血珠" tabindex="-1">无冥血珠 <a class="header-anchor" href="#无冥血珠" aria-label="Permalink to “无冥血珠”">​</a></h3><img src="'+h+'" alt="无冥血珠" style="zoom:50%;"><table tabindex="0"><thead><tr><th style="text-align:center;">被动</th><th style="text-align:center;">属性</th></tr></thead><tbody><tr><td style="text-align:center;">回血</td><td style="text-align:center;">15~20</td></tr><tr><td style="text-align:center;">回魔</td><td style="text-align:center;">9~12</td></tr><tr><td style="text-align:center;">吸血</td><td style="text-align:center;">12~17</td></tr><tr><td style="text-align:center;">反伤</td><td style="text-align:center;">12~17</td></tr></tbody></table>',27)])])}const g=a(n,[["render",i]]);export{m as __pageData,g as default};
